"use client";

import React from "react";
import Link from "next/link";
import { ArrowLeftIcon, Sparkles } from "lucide-react";
import { motion, useScroll, useSpring, useTransform } from "motion/react";

import { ModeToggle } from "@/components/mode-toggle";
import { AnimatedTabs } from "@/components/layouts/scroll-header/animated-tabs";

const tabs = [
  { label: "Home", value: "home", href: "/preview/layouts/scroll-header" },
  {
    label: "About",
    value: "about",
    href: "/preview/layouts/scroll-header/about",
  },
  {
    label: "Contact",
    value: "contact",
    href: "/preview/layouts/scroll-header/contact",
  },
  {
    label: "Danger Zone",
    value: "danger-zone",
    href: "/preview/layouts/scroll-header/danger-zone",
  },
];

// Spring profile tuned for scroll-linked motion: tight, near-critical damping,
// low mass. Responds quickly, settles cleanly, no visible overshoot.
const SCROLL_SPRING = { stiffness: 500, damping: 50, mass: 0.5 } as const;

export function ScrollHeader() {
  // Read the window scroll position as a motion value (rAF-driven,
  // passive listener, no React state, no re-renders per frame).
  const { scrollY } = useScroll();

  // Logo shrink: scale 1 → 0.8 over the first 33px of scroll.
  const logoScaleRaw = useTransform(scrollY, [0, 33], [1, 0.8], {
    clamp: true,
  });
  const logoScale = useSpring(logoScaleRaw, SCROLL_SPRING);

  // Tab strip nudges right 0 → 40px over the first 80px of scroll to
  // clear space for the shrunken logo corner.
  const tabXRaw = useTransform(scrollY, [0, 80], [0, 40], { clamp: true });
  const tabX = useSpring(tabXRaw, SCROLL_SPRING);

  return (
    <>
      <header className="relative w-full bg-background">
        <motion.div
          className="fixed left-0 top-0 z-50 pl-5 pt-5"
          style={{ scale: logoScale, transformOrigin: "0 0" }}
        >
          <div className="flex h-5 w-5 items-center justify-center rounded-md bg-foreground">
            <Sparkles className="h-3 w-3 text-background" />
          </div>
        </motion.div>

        <div className="flex items-center justify-between px-5 pb-0 pl-14 pt-3 font-mono">
          <div className="flex items-center gap-2">
            <Link
              href="/layouts"
              className="inline-flex items-center gap-1.5 text-sm font-medium text-muted-foreground transition-colors hover:text-foreground"
            >
              <ArrowLeftIcon className="h-3.5 w-3.5" />
              Layouts
            </Link>
            <span className="text-sm font-medium text-muted-foreground">/</span>
            <span className="text-sm font-medium">Scroll Header</span>
          </div>
          <div className="flex items-center justify-end gap-2">
            <ModeToggle />
          </div>
        </div>
      </header>

      <div className="sticky top-0 z-40 overflow-x-hidden border-b border-border bg-background">
        <div className="flex items-center justify-center">
          <motion.div
            className="flex flex-1 justify-center"
            style={{ x: tabX }}
          >
            <AnimatedTabs tabs={tabs} />
          </motion.div>
        </div>
      </div>
    </>
  );
}

"use client";

import React from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { AnimatePresence, motion, type Transition } from "motion/react";

import useTabs, { type Tab } from "@/hooks/layouts/use-tabs";
import { cn } from "@/lib/utils";

interface AnimatedTabsProps {
  tabs: Tab[];
}

const transition = {
  type: "tween",
  ease: "easeOut",
  duration: 0.15,
};

const getHoverAnimationProps = (hoveredRect: DOMRect, navRect: DOMRect) => ({
  x: hoveredRect.left - navRect.left - 10,
  y: hoveredRect.top - navRect.top - 4,
  width: hoveredRect.width + 20,
  height: hoveredRect.height + 10,
});

const Tabs = ({
  tabs,
  selectedTabIndex,
  setSelectedTab,
}: {
  tabs: Tab[];
  selectedTabIndex: number;
  setSelectedTab: (input: [number, number]) => void;
}) => {
  const [buttonRefs, setButtonRefs] = React.useState<
    Array<HTMLAnchorElement | null>
  >([]);

  React.useEffect(() => {
    setButtonRefs((prev) => prev.slice(0, tabs.length));
  }, [tabs.length]);

  const navRef = React.useRef<HTMLDivElement>(null);
  const navRect = navRef.current?.getBoundingClientRect();

  const selectedRect = buttonRefs[selectedTabIndex]?.getBoundingClientRect();

  const [hoveredTabIndex, setHoveredTabIndex] = React.useState<number | null>(
    null,
  );
  const hoveredRect =
    buttonRefs[hoveredTabIndex ?? -1]?.getBoundingClientRect();

  return (
    <nav
      ref={navRef}
      className="relative flex flex-shrink-0 items-center justify-center py-2"
      onPointerLeave={() => setHoveredTabIndex(null)}
    >
      {tabs.map((item, i) => {
        const isActive = selectedTabIndex === i;
        return (
          <Link
            key={item.value}
            href={item.href || "#"}
            className="relative z-20 flex h-8 cursor-pointer select-none items-center rounded-md bg-transparent px-4 transition-colors"
            onPointerEnter={() => setHoveredTabIndex(i)}
            onFocus={() => setHoveredTabIndex(i)}
            onClick={() => setSelectedTab([i, i > selectedTabIndex ? 1 : -1])}
          >
            <motion.span
              ref={(el) => {
                buttonRefs[i] = el as HTMLAnchorElement;
              }}
              className={cn("block text-sm", {
                "text-zinc-500": !isActive,
                "font-semibold text-black dark:text-white": isActive,
              })}
            >
              <span
                className={item.value === "danger-zone" ? "text-red-500" : ""}
              >
                {item.label}
              </span>
            </motion.span>
          </Link>
        );
      })}

      <AnimatePresence>
        {hoveredRect && navRect && (
          <motion.div
            key="hover"
            className={`absolute left-0 top-0 z-10 rounded-md ${
              hoveredTabIndex ===
              tabs.findIndex(({ value }) => value === "danger-zone")
                ? "bg-red-100 dark:bg-red-500/30"
                : "bg-zinc-100 dark:bg-zinc-800"
            }`}
            initial={{
              ...getHoverAnimationProps(hoveredRect, navRect),
              opacity: 0,
            }}
            animate={{
              ...getHoverAnimationProps(hoveredRect, navRect),
              opacity: 1,
            }}
            exit={{
              ...getHoverAnimationProps(hoveredRect, navRect),
              opacity: 0,
            }}
            transition={transition as Transition}
          />
        )}
      </AnimatePresence>

      <AnimatePresence>
        {selectedRect && navRect && (
          <motion.div
            className={`absolute bottom-0 left-0 z-10 h-[2px] ${
              selectedTabIndex ===
              tabs.findIndex(({ value }) => value === "danger-zone")
                ? "bg-red-500"
                : "bg-black dark:bg-white"
            }`}
            initial={false}
            animate={{
              width: selectedRect.width + 18,
              x: `calc(${selectedRect.left - navRect.left - 9}px)`,
              opacity: 1,
            }}
            transition={transition as Transition}
          />
        )}
      </AnimatePresence>
    </nav>
  );
};

export function AnimatedTabs({ tabs }: AnimatedTabsProps) {
  const pathname = usePathname();

  const [hookProps] = React.useState(() => {
    const matchedTab =
      tabs.find((tab) => tab.href && pathname?.startsWith(tab.href)) ?? tabs[0];
    return {
      tabs: tabs.map(({ label, value, subRoutes, href }) => ({
        label,
        value,
        subRoutes,
        href,
      })),
      initialTabId: matchedTab.value,
    };
  });

  const framer = useTabs(hookProps);

  return (
    <div className="relative flex w-full items-start justify-start overflow-x-auto overflow-y-hidden">
      <Tabs {...framer.tabProps} />
    </div>
  );
}

